insert into `challenges` (`answer_event_record_id`, `author_id`, `category`, `created_at`, `description`, `difficulty`, `flag`, `id`, `log_file_path`, `points`, `sigma_rule`, `status`, `title`) values ('32008', 1, 'Windows Events', '2026-04-16 13:19:28', ' Find PowerShell connecting to destination over ldap', 'medium', 'CTF{32008}', 1, './challenges_logs/discovery_sysmon_3_Invoke_UserHunter_SourceMachine_challenge_1776344935_challenge_1776345069.json', 100, 'title: Detection Rule for Invoke-UserHunter\nstatus: experimental\ndescription: Detect the PowerShell connecting to network ldap\nlogsource:\n  product: windows\n  service: sysmon\ndetection:\n  selection:\n    EventID: 3\n    Image|endswith: \'\\powershell.exe\'\n    DestinationPortName: \'ldap\'\n    User|endswith: \'Administrator\'\n  condition: selection\nlevel: high\n', 'published', 'ShadowReach 1 - Internal Network Enumeration');
